package com.example.reportgenerator.worker;
import com.example.reportgenerator.config.AppProperties;import com.example.reportgenerator.parser.LabReportXmlParser;import com.example.reportgenerator.report.ReportGenerator;import com.example.reportgenerator.storage.MinioArchiveService;import org.slf4j.*;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Component;import java.nio.file.*;import java.util.stream.Stream;
@Component
public class LabReportWorker { private static final Logger log=LoggerFactory.getLogger(LabReportWorker.class); private final AppProperties props; private final LabReportXmlParser parser; private final ReportGenerator generator; private final MinioArchiveService archive;
 public LabReportWorker(AppProperties p,LabReportXmlParser parser,ReportGenerator g,MinioArchiveService a){props=p;this.parser=parser;generator=g;archive=a;}
 @Scheduled(fixedDelayString="#{${app.poll-interval-seconds:10} * 1000}") public void poll(){ try{ Files.createDirectories(Path.of(props.incomingDir()));Files.createDirectories(Path.of(props.processedDir()));Files.createDirectories(Path.of(props.errorDir())); try(Stream<Path> s=Files.list(Path.of(props.incomingDir()))){ s.filter(p->p.toString().toLowerCase().endsWith(".xml")).forEach(this::processSafely); }}catch(Exception e){log.error("Polling failed",e);} }
 private void processSafely(Path xml){ Path lock=xml.resolveSibling(xml.getFileName()+".lock"); try{ Files.move(xml,lock,StandardCopyOption.ATOMIC_MOVE); byte[] bytes=Files.readAllBytes(lock); var report=parser.parse(new java.io.ByteArrayInputStream(bytes)); byte[] pdf=generator.generatePdf(report); archive.archive(report,xml.getFileName().toString(),bytes,pdf); Files.move(lock,Path.of(props.processedDir(),xml.getFileName().toString()),StandardCopyOption.REPLACE_EXISTING); log.info("Processed {}",xml); }catch(Exception e){ log.error("Processing failed for {}",xml,e); try{ Path err=Path.of(props.errorDir(),xml.getFileName().toString()); Path src=Files.exists(lock)?lock:xml; if(Files.exists(src)) Files.move(src,err,StandardCopyOption.REPLACE_EXISTING); Files.writeString(Path.of(props.errorDir(),xml.getFileName()+".log"),e.toString()); }catch(Exception move){log.error("Cannot move failed file",move);} } }
}
